from flask import Flask, request, jsonify
import psycopg2

app = Flask(__name__)

# Database connection configuration
DB_CONFIG = {
    'dbname': 'your_db_name',
    'user': 'your_username',
    'password': 'your_password',
    'host': 'your_host'
}

def get_db_connection():
    return psycopg2.connect(**DB_CONFIG)

@app.route('/query', methods=['POST'])
def query_database():
    data = request.get_json()
    
    table_name = data.get('table_name')
    columns = data.get('columns')
    conditions = data.get('conditions')

    if not table_name or not columns:
        return jsonify({'error': 'Missing required parameters'}), 400

    # Construct SQL query
    sql_query = f"SELECT {', '.join(columns)} FROM {table_name}"

    if conditions:
        condition_str = ' AND '.join([f"{cond['column']} = '{cond['value']}'" for cond in conditions])
        sql_query += f" WHERE {condition_str}"

    try:
        conn = get_db_connection()
        cursor = conn.cursor()
        cursor.execute(sql_query)
        result = cursor.fetchall()
        column_names = [desc[0] for desc in cursor.description]
        response_data = [dict(zip(column_names, row)) for row in result]
        return jsonify(response_data), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 500
    finally:
        if conn:
            conn.close()

if __name__ == '__main__':
    app.run(debug=True)